  def index(conn, _params) do
    commands = Commands.list_available_commands()
    json(conn, %{commands: commands})
  end

  def execute(conn, %{"command" => command_name} = params) do
    target = Map.get(params, "target")

    # Log the request for audit trail
    Logger.info("Command execution request",
      command: command_name,
      target: target,
      user: conn.assigns[:current_user],
      remote_ip: to_string(:inet_parse.ntoa(conn.remote_ip))
    )

    case Commands.execute(command_name, target) do
      {:ok, result} ->
        Logger.info("Command executed successfully",
          command: command_name,
          exit_code: result.exit_code
        )

        json(conn, %{
          status: "success",
          command: command_name,
          exit_code: result.exit_code,
          output: result.output
        })

      {:error, reason} ->
        Logger.warning("Command execution denied/failed",
          command: command_name,
          reason: reason
        )

        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: reason})
    end
  end

  def execute(conn, _params) do
